import{_ as n,o as s,c as t,a4 as l}from"./chunks/framework._in6GHBg.js";const x=JSON.parse('{"title":"函数与导数综合套路","description":"","frontmatter":{},"headers":[],"relativePath":"math/Math-Review-Routine-004-函数与导数套路-V1.0-20260405.md","filePath":"math/Math-Review-Routine-004-函数与导数套路-V1.0-20260405.md"}'),e={name:"math/Math-Review-Routine-004-函数与导数套路-V1.0-20260405.md"};function p(i,a,r,o,h,d){return s(),t("div",null,[...a[0]||(a[0]=[l(`<h1 id="函数与导数综合套路" tabindex="-1">函数与导数综合套路 <a class="header-anchor" href="#函数与导数综合套路" aria-label="Permalink to &quot;函数与导数综合套路&quot;">​</a></h1><p><strong>求导→分析→求解→验证</strong></p><hr><h2 id="一、题型识别" tabindex="-1">一、题型识别 <a class="header-anchor" href="#一、题型识别" aria-label="Permalink to &quot;一、题型识别&quot;">​</a></h2><h3 id="特征关键词" tabindex="-1">特征关键词 <a class="header-anchor" href="#特征关键词" aria-label="Permalink to &quot;特征关键词&quot;">​</a></h3><ul><li>&quot;求函数的单调区间&quot;</li><li>&quot;求函数的极值/最值&quot;</li><li>&quot;求参数的取值范围&quot;</li><li>&quot;证明不等式&quot;</li><li>&quot;讨论函数的零点个数&quot;</li><li>&quot;恒成立&quot;</li></ul><h3 id="典型问法" tabindex="-1">典型问法 <a class="header-anchor" href="#典型问法" aria-label="Permalink to &quot;典型问法&quot;">​</a></h3><ul><li>讨论f(x)的单调性</li><li>求f(x)在[a,b]上的最值</li><li>当x&gt;0时，f(x)≥0恒成立，求a的范围</li><li>证明：当x&gt;0时，eˣ &gt; x+1</li><li>求函数f(x)的零点个数</li></ul><hr><h2 id="二、解题步骤" tabindex="-1">二、解题步骤 <a class="header-anchor" href="#二、解题步骤" aria-label="Permalink to &quot;二、解题步骤&quot;">​</a></h2><h3 id="类型1-讨论单调性" tabindex="-1">类型1：讨论单调性 <a class="header-anchor" href="#类型1-讨论单调性" aria-label="Permalink to &quot;类型1：讨论单调性&quot;">​</a></h3><p><strong>Step 1：确定定义域</strong></p><ul><li>写出函数的定义域（分母≠0，对数真数&gt;0等）</li></ul><p><strong>Step 2：求导</strong></p><ul><li>计算f&#39;(x)，并化简</li></ul><p><strong>Step 3：求临界点</strong></p><ul><li>解f&#39;(x)=0，得x₁, x₂, ...</li><li>找出f&#39;(x)不存在的点</li></ul><p><strong>Step 4：列表分析</strong></p><ul><li>用临界点划分区间</li><li>判断各区间内f&#39;(x)的符号</li><li>确定单调性</li></ul><p><strong>标准格式</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>解：f(x)的定义域为[定义域]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>f&#39;(x) = [求导结果]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>令f&#39;(x)=0，得x = [临界点]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>列表：</span></span>
<span class="line"><span>x        (-∞,x₁)   x₁   (x₁,x₂)   x₂   (x₂,+∞)</span></span>
<span class="line"><span>f&#39;(x)       +       0       -       0       +</span></span>
<span class="line"><span>f(x)        ↗    极大    ↘    极小    ↗</span></span>
<span class="line"><span></span></span>
<span class="line"><span>∴ f(x)在[区间]单调递增，在[区间]单调递减</span></span></code></pre></div><hr><h3 id="类型2-求极值-最值" tabindex="-1">类型2：求极值/最值 <a class="header-anchor" href="#类型2-求极值-最值" aria-label="Permalink to &quot;类型2：求极值/最值&quot;">​</a></h3><p><strong>Step 1-3</strong>：同单调性</p><p><strong>Step 4：判断极值</strong></p><ul><li>f&#39;(x)左正右负 → 极大值</li><li>f&#39;(x)左负右正 → 极小值</li><li>f&#39;(x)不变号 → 不是极值</li></ul><p><strong>Step 5：求最值（闭区间）</strong></p><ul><li>计算极值点和端点的函数值</li><li>比较大小，最大者为最大值，最小者为最小值</li></ul><hr><h3 id="类型3-恒成立问题-求参数范围" tabindex="-1">类型3：恒成立问题（求参数范围） <a class="header-anchor" href="#类型3-恒成立问题-求参数范围" aria-label="Permalink to &quot;类型3：恒成立问题（求参数范围）&quot;">​</a></h3><p><strong>类型3.1：f(x) ≥ 0恒成立</strong></p><p><strong>Step 1：分离参数（若能）</strong></p><ul><li>将参数a分离到一边：a ≥ φ(x) 或 a ≤ φ(x)</li></ul><p><strong>Step 2：求最值</strong></p><ul><li>a ≥ φ(x)恒成立 → a ≥ φ(x)ₘₐₓ</li><li>a ≤ φ(x)恒成立 → a ≤ φ(x)ₘᵢₙ</li></ul><p><strong>Step 3：得出结论</strong></p><p><strong>类型3.2：无法分离参数</strong></p><p><strong>Step 1：构造函数</strong></p><ul><li>设g(x) = f(x)，视参数为常数</li></ul><p><strong>Step 2：求g(x)的最小值</strong></p><ul><li>求导，找极值点</li><li>g(x)ₘᵢₙ ≥ 0</li></ul><p><strong>Step 3：解关于参数的不等式</strong></p><hr><h3 id="类型4-证明不等式" tabindex="-1">类型4：证明不等式 <a class="header-anchor" href="#类型4-证明不等式" aria-label="Permalink to &quot;类型4：证明不等式&quot;">​</a></h3><p><strong>Step 1：构造函数</strong></p><ul><li>要证f(x) &gt; g(x)，设h(x) = f(x) - g(x)</li><li>目标：证明h(x) &gt; 0</li></ul><p><strong>Step 2：求h(x)的最小值</strong></p><ul><li>求导，找极值点</li><li>证明h(x)ₘᵢₙ &gt; 0</li></ul><p><strong>Step 3：得出结论</strong></p><p><strong>常用放缩不等式</strong>：</p><ul><li>eˣ ≥ x + 1（x∈R）</li><li>ln x ≤ x - 1（x &gt; 0）</li><li>eˣ ≥ ex（x ≥ 1）</li></ul><hr><h3 id="类型5-讨论零点个数" tabindex="-1">类型5：讨论零点个数 <a class="header-anchor" href="#类型5-讨论零点个数" aria-label="Permalink to &quot;类型5：讨论零点个数&quot;">​</a></h3><p><strong>Step 1：求导，确定单调性</strong></p><p><strong>Step 2：求极值</strong></p><p><strong>Step 3：分析极限</strong></p><ul><li>x→-∞时，f(x)→?</li><li>x→+∞时，f(x)→?</li></ul><p><strong>Step 4：结合极值符号判断零点个数</strong></p><table tabindex="0"><thead><tr><th style="text-align:center;">极大值</th><th style="text-align:center;">极小值</th><th style="text-align:center;">零点个数</th></tr></thead><tbody><tr><td style="text-align:center;">+</td><td style="text-align:center;">-</td><td style="text-align:center;">3个</td></tr><tr><td style="text-align:center;">+</td><td style="text-align:center;">+</td><td style="text-align:center;">1个（左）</td></tr><tr><td style="text-align:center;">-</td><td style="text-align:center;">-</td><td style="text-align:center;">1个（右）</td></tr><tr><td style="text-align:center;">-</td><td style="text-align:center;">+</td><td style="text-align:center;">0个</td></tr><tr><td style="text-align:center;">=0</td><td style="text-align:center;">&lt;0</td><td style="text-align:center;">2个（极大值点在x轴上）</td></tr></tbody></table><hr><h2 id="三、标准格式" tabindex="-1">三、标准格式 <a class="header-anchor" href="#三、标准格式" aria-label="Permalink to &quot;三、标准格式&quot;">​</a></h2><h3 id="单调性答题模板" tabindex="-1">单调性答题模板 <a class="header-anchor" href="#单调性答题模板" aria-label="Permalink to &quot;单调性答题模板&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>解：f(x)的定义域为[定义域]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>f&#39;(x) = [求导结果] = [因式分解]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>令f&#39;(x)=0，得x₁=..., x₂=...</span></span>
<span class="line"><span></span></span>
<span class="line"><span>当x∈(区间1)时，f&#39;(x)&gt;0，f(x)单调递增；</span></span>
<span class="line"><span>当x∈(区间2)时，f&#39;(x)&lt;0，f(x)单调递减。</span></span></code></pre></div><h3 id="恒成立答题模板" tabindex="-1">恒成立答题模板 <a class="header-anchor" href="#恒成立答题模板" aria-label="Permalink to &quot;恒成立答题模板&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>解：f(x)≥0恒成立，即[f(x)]ₘᵢₙ≥0</span></span>
<span class="line"><span></span></span>
<span class="line"><span>f&#39;(x) = ...</span></span>
<span class="line"><span>...</span></span>
<span class="line"><span></span></span>
<span class="line"><span>f(x)在x=...处取得最小值...</span></span>
<span class="line"><span></span></span>
<span class="line"><span>∴ ... ≥ 0，解得a∈[范围]</span></span></code></pre></div><hr><h2 id="四、典型例题" tabindex="-1">四、典型例题 <a class="header-anchor" href="#四、典型例题" aria-label="Permalink to &quot;四、典型例题&quot;">​</a></h2><h3 id="例题1-讨论单调性" tabindex="-1">例题1：讨论单调性 <a class="header-anchor" href="#例题1-讨论单调性" aria-label="Permalink to &quot;例题1：讨论单调性&quot;">​</a></h3><p><strong>题目</strong>：讨论f(x) = x³ - 3x²的单调性。</p><p><strong>解答</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>解：f(x)的定义域为R</span></span>
<span class="line"><span></span></span>
<span class="line"><span>f&#39;(x) = 3x² - 6x = 3x(x-2)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>令f&#39;(x)=0，得x=0或x=2</span></span>
<span class="line"><span></span></span>
<span class="line"><span>当x∈(-∞,0)时，f&#39;(x)&gt;0，f(x)单调递增；</span></span>
<span class="line"><span>当x∈(0,2)时，f&#39;(x)&lt;0，f(x)单调递减；</span></span>
<span class="line"><span>当x∈(2,+∞)时，f&#39;(x)&gt;0，f(x)单调递增。</span></span></code></pre></div><hr><h3 id="例题2-恒成立问题" tabindex="-1">例题2：恒成立问题 <a class="header-anchor" href="#例题2-恒成立问题" aria-label="Permalink to &quot;例题2：恒成立问题&quot;">​</a></h3><p><strong>题目</strong>：当x&gt;0时，f(x) = eˣ - ax - 1 ≥ 0恒成立，求a的取值范围。</p><p><strong>解答</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>解：f(x)≥0恒成立，即f(x)ₘᵢₙ≥0</span></span>
<span class="line"><span></span></span>
<span class="line"><span>f&#39;(x) = eˣ - a</span></span>
<span class="line"><span></span></span>
<span class="line"><span>令f&#39;(x)=0，得eˣ=a，即x=ln a（需a&gt;0）</span></span>
<span class="line"><span></span></span>
<span class="line"><span>当a≤0时，f&#39;(x)=eˣ-a&gt;0，f(x)单调递增</span></span>
<span class="line"><span>f(x)&gt;f(0)=0，满足条件</span></span>
<span class="line"><span></span></span>
<span class="line"><span>当a&gt;0时：</span></span>
<span class="line"><span>- x∈(0,ln a)时，f&#39;(x)&lt;0，f(x)递减</span></span>
<span class="line"><span>- x∈(ln a,+∞)时，f&#39;(x)&gt;0，f(x)递增</span></span>
<span class="line"><span></span></span>
<span class="line"><span>f(x)ₘᵢₙ = f(ln a) = a - a·ln a - 1</span></span>
<span class="line"><span></span></span>
<span class="line"><span>令g(a) = a - a·ln a - 1（a&gt;0）</span></span>
<span class="line"><span>g&#39;(a) = 1 - ln a - 1 = -ln a</span></span>
<span class="line"><span></span></span>
<span class="line"><span>当a∈(0,1)时，g&#39;(a)&gt;0，g(a)递增</span></span>
<span class="line"><span>当a∈(1,+∞)时，g&#39;(a)&lt;0，g(a)递减</span></span>
<span class="line"><span></span></span>
<span class="line"><span>g(a)ₘₐₓ = g(1) = 0</span></span>
<span class="line"><span></span></span>
<span class="line"><span>∴ g(a)≤0，即f(x)ₘᵢₙ≤0</span></span>
<span class="line"><span></span></span>
<span class="line"><span>要使f(x)ₘᵢₙ≥0，需g(a)≥0，即a=1</span></span>
<span class="line"><span></span></span>
<span class="line"><span>综上，a≤1</span></span></code></pre></div><hr><h2 id="五、变式训练" tabindex="-1">五、变式训练 <a class="header-anchor" href="#五、变式训练" aria-label="Permalink to &quot;五、变式训练&quot;">​</a></h2><h3 id="变式1-含参数的单调性讨论" tabindex="-1">变式1：含参数的单调性讨论 <a class="header-anchor" href="#变式1-含参数的单调性讨论" aria-label="Permalink to &quot;变式1：含参数的单调性讨论&quot;">​</a></h3><ul><li>导函数含参数，需分类讨论</li><li>关键：讨论临界值（使导数恒正/恒负/有零点的参数值）</li></ul><h3 id="变式2-端点效应" tabindex="-1">变式2：端点效应 <a class="header-anchor" href="#变式2-端点效应" aria-label="Permalink to &quot;变式2：端点效应&quot;">​</a></h3><ul><li>恒成立问题中，端点值等于0</li><li>应对：先由端点值必要条件缩小参数范围，再证明充分性</li></ul><h3 id="变式3-隐零点问题" tabindex="-1">变式3：隐零点问题 <a class="header-anchor" href="#变式3-隐零点问题" aria-label="Permalink to &quot;变式3：隐零点问题&quot;">​</a></h3><ul><li>极值点无法显式求出</li><li>应对：设极值点为x₀，利用f&#39;(x₀)=0化简，整体代换</li></ul><hr><h2 id="六、易错点清单" tabindex="-1">六、易错点清单 <a class="header-anchor" href="#六、易错点清单" aria-label="Permalink to &quot;六、易错点清单&quot;">​</a></h2><h3 id="审题阶段" tabindex="-1">审题阶段 <a class="header-anchor" href="#审题阶段" aria-label="Permalink to &quot;审题阶段&quot;">​</a></h3><ul><li>[ ] 定义域是否考虑？</li><li>[ ] 是开区间还是闭区间？</li><li>[ ] 是恒成立还是存在性？</li></ul><h3 id="计算阶段" tabindex="-1">计算阶段 <a class="header-anchor" href="#计算阶段" aria-label="Permalink to &quot;计算阶段&quot;">​</a></h3><ul><li>[ ] 求导是否正确？</li><li>[ ] 临界点是否找全？</li><li>[ ] 极值点是否在定义域内？</li></ul><h3 id="检验阶段" tabindex="-1">检验阶段 <a class="header-anchor" href="#检验阶段" aria-label="Permalink to &quot;检验阶段&quot;">​</a></h3><ul><li>[ ] 参数范围端点是否可取？</li><li>[ ] 特殊情况是否验证？</li></ul><hr><h2 id="七、得分点提示" tabindex="-1">七、得分点提示 <a class="header-anchor" href="#七、得分点提示" aria-label="Permalink to &quot;七、得分点提示&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:center;">步骤</th><th style="text-align:left;">得分点</th></tr></thead><tbody><tr><td style="text-align:center;">定义域</td><td style="text-align:left;">写出定义域</td></tr><tr><td style="text-align:center;">求导</td><td style="text-align:left;">写出f&#39;(x)</td></tr><tr><td style="text-align:center;">临界点</td><td style="text-align:left;">解f&#39;(x)=0</td></tr><tr><td style="text-align:center;">单调性</td><td style="text-align:left;">列表或文字说明</td></tr><tr><td style="text-align:center;">极值</td><td style="text-align:left;">写出极大/极小值</td></tr><tr><td style="text-align:center;">最值</td><td style="text-align:left;">比较端点和极值</td></tr></tbody></table><hr><p><strong>文档编号</strong>: Math-Review-Routine-004<br><strong>版本</strong>: V1.0<br><strong>日期</strong>: 20260405</p>`,97)])])}const g=n(e,[["render",p]]);export{x as __pageData,g as default};
